import { useState, useEffect, useCallback } from 'react';
import encryptionService from '../utils/encryptionService';

/**
 * React hook for using encrypted storage in components.
 */
export function useEncryptedStorage(key, initialValue = null) {
  const [value, setValue] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const load = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const stored = await encryptionService.getEncrypted(key);
      if (stored !== null) {
        setValue(stored);
      }
    } catch (err) {
      setError(err);
      console.error(`Failed to load encrypted data for key "${key}":`, err);
    } finally {
      setLoading(false);
    }
  }, [key]);

  const save = useCallback(async (newValue) => {
    try {
      setError(null);
      await encryptionService.saveEncrypted(key, newValue);
      setValue(newValue);
    } catch (err) {
      setError(err);
      console.error(`Failed to save encrypted data for key "${key}":`, err);
      throw err;
    }
  }, [key]);

  const remove = useCallback(async () => {
    try {
      setError(null);
      await encryptionService.deleteEncrypted(key);
      setValue(null);
    } catch (err) {
      setError(err);
      console.error(`Failed to delete encrypted data for key "${key}":`, err);
      throw err;
    }
  }, [key]);

  useEffect(() => {
    load();
  }, [load]);

  return { value, loading, error, save, remove, reload: load };
}

